const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'sprint-planning': {
    system: `You are an expert agile coach and engineering leader. Create detailed, realistic sprint plans. Be specific about capacity, trade-offs, and risks. Output in clean markdown.`,
    user: `Create a sprint plan:

Sprint goal: ${inputs.sprint_goal || ''}
Team capacity: ${inputs.capacity || ''} (e.g. "4 engineers × 8 days = 32 eng-days")
Backlog items to consider: ${inputs.backlog || ''}
Velocity (last 3 sprints): ${inputs.velocity || 'not provided'}
Known risks or blockers: ${inputs.risks || 'none'}

Output: sprint goal statement, committed work with estimates, stretch goals, capacity breakdown, risks, and definition of done.`
  },

  'quarterly-planning': {
    system: `You are an expert product and engineering leader. Create focused quarterly plans with clear themes, bets, and resource allocation. Avoid vague objectives — every item should be specific and measurable. Output in clean markdown.`,
    user: `Create a quarterly plan:

Company/team: ${inputs.company || ''}
Quarter: ${inputs.quarter || ''}
Annual goals this quarter serves: ${inputs.annual_goals || ''}
Available resources: ${inputs.resources || ''}
Key constraints: ${inputs.constraints || ''}
Top opportunities: ${inputs.opportunities || ''}

Output: 2-3 quarterly themes, 4-6 specific bets with success metrics, resource allocation per theme, key risks, and a weekly milestone skeleton.`
  },

  'sprint-retro': {
    system: `You are an expert agile facilitator. Structure sprint retrospectives that surface real issues and produce actionable improvements — not just feel-good exercises. Use the Start/Stop/Continue format with a focus on concrete action items. Output in clean markdown.`,
    user: `Facilitate a sprint retrospective:

Team: ${inputs.team || ''}
Sprint number/dates: ${inputs.sprint || ''}
What went well: ${inputs.went_well || ''}
What didn't go well: ${inputs.went_poorly || ''}
Metrics this sprint: ${inputs.metrics || ''}
Previous retro action items (completed?): ${inputs.previous_actions || 'not provided'}

Output: Start/Stop/Continue synthesis, root cause analysis for top 2 problems, 3 specific action items with owners and due dates, and one experiment to try next sprint.`
  },

  'feature-decomposition': {
    system: `You are an expert product manager and engineer. Break down features into shippable chunks with clear dependencies, risks, and sequencing. Every chunk should be independently shippable and testable. Output in clean markdown.`,
    user: `Break down this feature into shippable chunks:

Feature: ${inputs.feature || ''}
User story: ${inputs.user_story || ''}
Tech stack/constraints: ${inputs.tech_stack || ''}
Team size: ${inputs.team_size || ''}
Deadline: ${inputs.deadline || 'none'}

Output: feature overview, ordered list of shippable chunks (each with scope, acceptance criteria, estimated effort, dependencies), dependency map, risks, and recommended sequencing with rationale.`
  },

  'backlog-prioritizer': {
    system: `You are an expert product manager. Prioritize backlogs using RICE (Reach, Impact, Confidence, Effort) scoring. Be explicit about your scoring assumptions. Show your math. Output in clean markdown with a prioritized table.`,
    user: `Prioritize this backlog:

Items to prioritize: ${inputs.items || ''}
Strategic context: ${inputs.context || ''}
Framework preference: ${inputs.framework || 'RICE'}
Team capacity: ${inputs.capacity || 'not specified'}
Current quarter focus: ${inputs.focus || 'not specified'}

Output: scored and ranked table with RICE scores, top 5 recommended items with rationale, items to defer and why, and any dependencies to flag.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;
return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
